// ESP32 Touch + LEDC + DAC Lab
// Board-specific features not available on classic AVR Arduino:
// 1) touchRead() capacitive input (T0 on GPIO4)
// 2) LEDC hardware PWM engine
// 3) dacWrite() analog output (GPIO25)

#if !defined(ARDUINO_ARCH_ESP32)
#error This sketch targets ESP32 only (wokwi-esp32-devkit-v1).
#endif

const int TOUCH_PIN = 4;     // T0
const int LED_PIN = 18;
const int DAC_PIN = 25;

const int LEDC_CHANNEL = 0;
const int LEDC_FREQ = 5000;
const int LEDC_RES = 8;

int touchBaseline = 0;

int readTouchAverage() {
  long sum = 0;
  for (int i = 0; i < 8; i++) {
    sum += touchRead(TOUCH_PIN);
    delay(2);
  }
  return (int)(sum / 8);
}

void setup() {
  Serial.begin(115200);
  delay(200);
  Serial.println("ESP32 Touch + LEDC + DAC Lab");

  ledcSetup(LEDC_CHANNEL, LEDC_FREQ, LEDC_RES);
  ledcAttachPin(LED_PIN, LEDC_CHANNEL);

  touchBaseline = readTouchAverage();
  Serial.print("Touch baseline: ");
  Serial.println(touchBaseline);
}

void loop() {
  int touch = readTouchAverage();
  int delta = touchBaseline - touch;
  if (delta < 0) delta = 0;

  int brightness = map(delta, 0, 50, 0, 255);
  brightness = constrain(brightness, 0, 255);
  ledcWrite(LEDC_CHANNEL, brightness);

  // Map touch pressure to DAC waveform amplitude-ish value
  // (FUNDI bridge currently focuses on serial + lifecycle, but this compiles/runs on real ESP32)
  int dacValue = map(brightness, 0, 255, 0, 255);
  dacWrite(DAC_PIN, dacValue);

  Serial.print("touch=");
  Serial.print(touch);
  Serial.print(" delta=");
  Serial.print(delta);
  Serial.print(" pwm=");
  Serial.print(brightness);
  Serial.print(" dac=");
  Serial.println(dacValue);

  delay(100);
}
